import re
app = Flask(__name__)

def check_hate_speech(text):
    hate_words = ["hate", "racist", "homophobe"]
    skip_words = ["hates", "hated"]

    text_lower = text.lower()
    bad_words = []

    for hword in hate_words:
        pattern = r"\b" + hword + r"\b"
        if re.search(pattern, text_lower):
            is_bad_word = True
            for s in skip_words:
                pattern = r"\b" + s + r"\b"
                if re.search(pattern, text_lower):
                    is_bad_word = False
                    break

            if is_bad_word:
                bad_words.append(hword)

    return bad_words

@app.route("/set_comment", methods=['POST'])
def set_comment():
    text = request.json['text']

    bad_words = check_hate_speech(text)
    if bad_words:
        return "This comment contains the following hate words: " + ", ".join(bad_words)

    return "Your comment was accepted."

